  class SQLQueryValidator(spark: SparkSession) {
    
    private val deniedKeywords = Set(
      "DROP", "DELETE", "TRUNCATE", "INSERT", "UPDATE", 
      "CREATE", "ALTER", "GRANT", "REVOKE", "MERGE"
    )

    private val maxResultRows = 100000
    private val maxQueryComplexity = 10

    def validateQuery(query: String): Either[String, String] = {
      val normalizedQuery = query.trim.toUpperCase

      if (normalizedQuery.isEmpty) {
        return Left("Query cannot be empty")
      }

      val foundDeniedKeywords = deniedKeywords.filter(keyword =>
        normalizedQuery.matches(s".*\\b$keyword\\b.*")
      )

      if (foundDeniedKeywords.nonEmpty) {
        return Left(s"Query contains forbidden keywords: ${foundDeniedKeywords.mkString(", ")}")
      }

      if (!normalizedQuery.startsWith("SELECT") && 
          !normalizedQuery.startsWith("WITH") &&
          !normalizedQuery.startsWith("SHOW") &&
          !normalizedQuery.startsWith("DESCRIBE")) {
        return Left("Only SELECT, WITH, SHOW, and DESCRIBE queries are allowed")
      }

      Try {
        spark.sessionState.sqlParser.parsePlan(query)
      } match {
        case Success(logicalPlan) =>
          if (calculateQueryComplexity(logicalPlan) > maxQueryComplexity) {
            Left(s"Query complexity exceeds maximum allowed complexity of $maxQueryComplexity")
          } else {
            Right(query)
          }
        case Failure(e: ParseException) =>
          Left(s"SQL syntax error: ${e.getMessage}")
        case Failure(e) =>
          Left(s"Query validation failed: ${e.getMessage}")
      }
    }

    private def calculateQueryComplexity(plan: LogicalPlan): Int = {
      var complexity = 0
      plan.foreach { node =>
        complexity += 1
      }
      complexity
    }

    def validateResultSize(df: DataFrame): Either[String, DataFrame] = {
      Try {
        val count = df.count()
        if (count > maxResultRows) {
          Left(s"Result set too large: $count rows (max: $maxResultRows)")
        } else {
          Right(df)
        }
      } match {
        case Success(result) => result
        case Failure(e) => Left(s"Failed to validate result size: ${e.getMessage}")
      }
    }
  }

  class QueryExecutor(spark: SparkSession) {
    
