            )
          } match {
            case Success(response) => response
            case Failure(e) =>
              spark.sparkContext.cancelJobGroup(request.queryId)
              QueryResponse(
                queryId = request.queryId,
                status = "FAILED",
                error = Some(s"Failed to collect results: ${e.getMessage}"),
                executionTimeMs = System.currentTimeMillis() - startTime
              )
          }
        case Success(Left(error)) =>
          QueryResponse(
            queryId = request.queryId,
            status = "FAILED",
            error = Some(error),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
        case Failure(e) =>
          spark.sparkContext.cancelJobGroup(request.queryId)
          QueryResponse(
            queryId = request.queryId,
            status = "FAILED",
            error = Some(s"Query execution failed: ${e.getMessage}"),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
      }
    }

    def explainQuery(query: String): Either[String, String] = {
